namespace InventoryApp.Services;

public record EquipmentItem(int Id, string Name, string Location, DateTime LastInspected);

public interface IEquipmentService
{
    Task<List<EquipmentItem>> GetEquipmentAsync();
}

public class EquipmentService : IEquipmentService
{
    public async Task<List<EquipmentItem>> GetEquipmentAsync()
    {
        // Simulate a network/database delay
        await Task.Delay(500);

        return new List<EquipmentItem>
        {
            new(1, "Hydraulic Press", "Building A - Floor 1", new DateTime(2026, 3, 12)),
            new(2, "CNC Lathe", "Building A - Floor 2", new DateTime(2026, 4, 5)),
            new(3, "Forklift #7", "Warehouse B", new DateTime(2026, 5, 1)),
            new(4, "Conveyor Belt Motor", "Building C - Line 3", new DateTime(2026, 2, 20)),
            new(5, "Air Compressor", "Utility Room", new DateTime(2026, 1, 15)),
            new(6, "Welding Station #2", "Building A - Floor 1", new DateTime(2026, 4, 28)),
            new(7, "Overhead Crane", "Warehouse B", new DateTime(2025, 12, 10)),
            new(8, "Industrial Oven", "Building C - Line 1", new DateTime(2026, 5, 18)),
        };
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using InventoryApp.Services
@inject IEquipmentService EquipmentService
@inject PersistentComponentState ApplicationState
@implements IDisposable

<PageTitle>Inventory</PageTitle>

<h1>Equipment Inventory</h1>

@if (_items is null)
{
    <p><em>Loading inventory...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Id</th>
                <th>Name</th>
                <th>Location</th>
                <th>Last Inspected</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr>
                    <td>@item.Id</td>
                    <td>@item.Name</td>
                    <td>@item.Location</td>
                    <td>@item.LastInspected.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<EquipmentItem>? _items;
    private PersistingComponentStateSubscription _persistingSubscription;

    protected override async Task OnInitializedAsync()
    {
        _persistingSubscription = ApplicationState.RegisterOnPersisting(PersistData);

        // If data was persisted during prerender, restore it instead of fetching again.
        if (ApplicationState.TryTakeFromJson<List<EquipmentItem>>("equipment", out var restored))
        {
            _items = restored;
        }
        else
        {
            _items = await EquipmentService.GetEquipmentAsync();
        }
    }

    private Task PersistData()
    {
        ApplicationState.PersistAsJson("equipment", _items);
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        _persistingSubscription.Dispose();
    }
}

